// Queen Episode — Lotus Cycle experience record
// φ² + 1/φ² = 3 | TRINITY

const std = @import("std");

/// ═══════════════════════════════════════════════════════════════════
// EPISODE SOURCE TYPES
// ═══════════════════════════════════════════════════════════════════════════
pub const Source = enum(u8) {
    /// Internal Lotus Cycle (self-triggered by autonomous loop)
    lotus_cycle = 0,

    /// External trigger (user command, webhook, alert)
    external = 1,

    /// Scheduled (periodic check, watchdog timer)
    scheduled = 2,

    /// Experience recall (from similar past episodes)
    experience_recall = 3,
};

/// ═══════════════════════════════════════════════════════════════
// POLICY SNAPSHOT — Queen state before action
// ═══════════════════════════════════════════════════════════════════════════════════════
pub const PolicySnapshot = struct {
    /// Rate limit levels for various actions
    kill_threshold: f64 = 4.0,
    crash_rate_limit: f64 = 0.2,
    byzantine_rate_limit: f64 = 0.15,
    hslm_optimizer_steps: i64 = 1000,
    arena_battle_limit: u8 = 3,

    /// Governance flags
    god_mode: bool = true,
    require_human_approval: bool = false,
    max_auto_level: u8 = 2,

    /// Cooldown tracking (timestamp of last use)
    last_farm_status_ts: u64 = 0,
    last_cloud_spawn_ts: u64 = 0,
    last_train_status_ts: u64 = 0,
};

/// ═════════════════════════════════════════════════════════════════════════
// SENSORS SNAPSHOT — Real-time Queen metrics
// ═══════════════════════════════════════════════════════════════════════════════════════════════
pub const SensorsSnapshot = struct {
    /// Build status
    build_ok: bool = true,
    test_rate: f64 = 100.0,
    dirty_files: u32 = 0,
    last_build_ok: bool = true,

    /// Farm metrics
    farm_services: u32 = 104,
    farm_best_ppl: f64 = 2.04,
    farm_idle_count: u32 = 0,

    /// Arena battles
    arena_battles: u32 = 28,

    /// Ouroboros score
    ouroboros_score: f64 = 0.0,

    /// Network status
    network_ok: bool = true,

    /// System metrics
    disk_free_gb: f64 = 27.7,
    agent_count: u32 = 0,

    /// Experience base size
    experience_episodes: u32 = 197,
};

/// ═════════════════════════════════════════════════════════════════════════════
// CONTEXT — Queen's state before taking action
// ═══════════════════════════════════════════════════════════════════════════════════════════════════════
pub const Context = struct {
    /// When this context was captured
    timestamp_ns: u64,

    /// Policy state snapshot
    policy: PolicySnapshot,

    /// Sensor readings
    senses: SensorsSnapshot,

    /// Similar episodes recalled from experience
    recalled_episodes: []const *Episode,

    /// Active issues/tasks in queue
    active_issues: []const u64,
};

/// ═════════════════════════════════════════════════════════════════════════════════════════════════
// ACTION TYPES — What can be done in Lotus Cycle
// ═════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════════