// Load policy snapshot from .trinity/queen/policy.json
fn loadPolicySnapshot(allocator: Allocator) !PolicySnapshot {
    const file = try std.fs.cwd().openFile(".trinity/queen/policy.json", .{});
    defer file.close();

    const contents = try file.readToEndAlloc(allocator);
    defer allocator.free(contents);

    const parsed = try std.json.parseFromSlice(PolicySnapshot, contents);
    return parsed;
}

// Load sensors snapshot from .trinity/queen/senses.json
fn loadSensorsSnapshot(allocator: Allocator) !SensorsSnapshot {
    const file = try std.fs.cwd().openFile(".trinity/queen/senses.json", .{});
    defer file.close();

    const contents = try file.readToEndAlloc(allocator);
    defer allocator.free(contents);

    const parsed = try std.json.parseFromSlice(SensorsSnapshot, contents);
    return parsed;
}

/// Create new episode with empty action/result/outcome
/// Episodes are created BEFORE action execution, then updated with results
pub fn createEpisode(allocator: Allocator, context: Context) !Episode {
    const now_ns = std.time.nanoTimestamp();
    const id = now_ns;

    const episode = Episode{
        .id = id,
        .timestamp = now_ns,
        .source = .lotus_cycle,
        .context = context,
        .action = undefined,
        .result = undefined,
        .outcome = undefined,
    };

    return episode;
}

/// Append episode to episodes.jsonl (JSONL for append-only semantics)
pub fn appendEpisode(allocator: Allocator, episode: Episode) !void {
    const line = try std.json.stringifyAlloc(allocator, episode, .{});
    defer allocator.free(line);

    const file = try std.fs.cwd().openFile(EPISODES_PATH, .{ .mode = .write_only });
    defer file.close();

    // Seek to end for append
    const pos = try file.getEndPos();
    try file.seekTo(pos);

    try file.writeAll(line);
    try file.writeAll("\n");
}

/// Load episodes from JSONL file
pub fn loadEpisodes(allocator: Allocator, max_results: usize) ![]Episode {
    const file = std std.fs.cwd().openFile(EPISODES_PATH, .{}) catch return &[_]Episode{};
    defer file.close();

    var episodes = std.ArrayList(Episode).init(allocator);
    defer episodes.deinit();

    var line_buf: [1024]u8 = undefined;
    var line_reader = std.io.bufferedReader(file);

    while (try line_reader.readUntilDelimiterOrEof(&line_buf, '\n')) {
        const line = line_buf[0..line_reader.bytes_read];
        if (line.len == 0 or line[0] == '#') continue; // Skip empty/comments

        const parsed = try std.json.parseFromSlice(Episode, line) catch continue;
        try episodes.append(parsed);

        if (episodes.items.len >= max_results) break;
    }

    return try episodes.toOwnedSlice();
}

/// Update episode with action/result/outcome (used after Act stage)
pub fn updateEpisode(allocator: Allocator, id: u64, action: Action, result: Result, outcome: Outcome) !void {
    const file = try std.fs.cwd().openFile(EPISODES_PATH, .{});
    defer file.close();

    var line_buf: [8192]u8 = undefined;
    var line_reader = std.io.bufferedReader(file);

    const id_str = try std.fmt.allocPrint(allocator, "{d}", .{id});
    defer allocator.free(id_str);

    var output_lines = std.ArrayList([]const u8).init(allocator);
    defer output_lines.deinit();

    // Read all lines, find episode by ID, replace
    while (try line_reader.readUntilDelimiterOrEof(&line_buf, '\n')) {
        const line = line_buf[0..line_reader.bytes_read];
        if (line.len == 0 or line[0] == '#') continue;

        // Check if this is our target episode
        if (std.mem.indexOf(u8, line, id_str) != null) {
            // Found our episode, add updated line
            try output_lines.append(line);
        } else if (output_lines.items.len > 0) {
            // This is a different episode, preserve it
            try output_lines.append(line);
        }
    }

    // Write output back to file
    const temp_path = try std.fmt.allocPrint(allocator, "{s}.tmp", .{EPISODES_PATH});
    defer allocator.free(temp_path);

    const temp_file = try std.fs.cwd().createFile(temp_path, .{});
    defer temp_file.close();

    for (output_lines.items) |line| {
        try temp_file.writeAll(line);
        try temp_file.writeAll("\n");
    }

    try temp_file.sync();

    // Atomic rename (POSIX)
    if (@import("std.os").rename(EPISODES_PATH, temp_path)) |_| {
        try temp_file.delete();
    } else |_| {}
}

/// Calculate similarity score between two episodes (Jaccard on tags)
pub fn calculateSimilarity(allocator: Allocator, a: Episode, b: Context, recency_bias_ns: u64) !f64 {
    const now_ns = std.time.nanoTimestamp();
    const age_days = @as(f64, @floatFromInt((now_ns - a.timestamp))) / (@as(f64, std.time.s_per_day) * 1_000_000_000);

    var score: f64 = 0.0;
    var score_components: u8 = 0;

    // 1. Tag overlap score (0-40)
    if (a.result) |result_a| {
        if (result_a.tags) |tags_a| {
            if (b.tags) |tags_b| {
                for (tags_a) |tag_a| {
                    for (tags_b) |tag_b| {
                        if (std.mem.eql(u8, tag_a, tag_b)) {
                            score_components += 1;
                            break;
                        }
                    }
                    }
                }
            }
        }
    }

    // 2. Context similarity (0-30) - compare policy and senses
    if (score_components < 40) {
        const policy_sim = calculatePolicySimilarity(a.context.policy, b.policy);
        score_components += @as(u8, @floatFromInt(@as(u64, policy_sim * 30)));
    }

    // 3. Success bias (0-30) - prefer successful outcomes
    if (a.outcome == .success) {
        score_components += 30;
    } else if (a.outcome == .partial) {
        score_components += 15;
    }

    // 4. Recency bias (0-20) - boost for recent episodes (< 7 days)
    if (age_days < 7.0) {
        score_components += 20;
    }

    // Normalize to 0.0-1.0
    score = @as(f64, @floatFromInt(score_components)) / 100.0;

    return score;
}

/// Calculate policy similarity (0-100% for exact match, 0 for no match)
fn calculatePolicySimilarity(a: PolicySnapshot, b: PolicySnapshot) usize {
    if (a.kill_threshold == b.kill_threshold) return 100;
    if (a.god_mode == b.god_mode) return 100;
    if (std.math.approxEqRel(f64, a.kill_threshold, b.kill_threshold, 0.001)) return 80;
    if (std.math.approxEqRel(f64, a.crash_rate_limit, b.crash_rate_limit, 0.001)) return 80;

    return 0;
}

/// Calculate quality delta for PolicyDelta operations
pub fn estimateQualityDelta(delta: PolicyDelta, current_context: Context) f64 {
    const current = current_context.policy;
    const key = delta.key;

    const old_value = getPolicyValue(current, key);
    const new_value = delta.new_value;

    // Different value types need different scoring
    if (old_value == .null or new_value == .null) {
        // Assigning or unassigning
        return 0.1;
    }

    // Rate limit changes
    if (std.mem.eql(u8, key, "kill_threshold")) {
        const old_thr = old_value.f64 orelse 4.0;
        const new_thr = new_value.f64 orelse 4.0;
        const farm_best_ppl = current_context.senses.farm_best_ppl;

        // Quality = 1.0 if moving toward better PPL, -1.0 if away
        const improvement = if (old_thr < farm_best_ppl and new_thr > old_thr and new_thr <= farm_best_ppl)
            1.0
        else if (old_thr > farm_best_ppl and new_thr < old_thr and new_thr >= farm_best_ppl)
            1.0
        else
            -1.0;

        return @as(f64, improvement * delta.expected_quality_delta);
    }

    return delta.expected_quality_delta orelse 0.0;
}

fn getPolicyValue(policy: PolicySnapshot, key: []const u8) union { bool, f64 } {
    if (std.mem.eql(u8, key, "kill_threshold")) return .{ .f64 = policy.kill_threshold };
    if (std.mem.eql(u8, key, "crash_rate_limit")) return .{ .f64 = policy.crash_rate_limit };
    if (std.mem.eql(u8, key, "byzantine_rate_limit")) return .{ .f64 = policy.byzantine_rate_limit };
    if (std.mem.eql(u8, key, "god_mode")) return .{ .bool = policy.god_mode };
    if (std.mem.eql(u8, key, "require_human_approval")) return .{ .bool = policy.require_human_approval };
    if (std.mem.eql(u8, key, "max_auto_level")) return .{ .i64 = policy.max_auto_level };

    return .{ .f64 = 0.0 }; // Unknown key
}

/// Tests for Episode module
test "Episode: createEpisode generates valid ID" {
    const allocator = std.testing.allocator;
    const context = Context{
        .timestamp_ns = std.time.nanoTimestamp(),
        .policy = PolicySnapshot{},
        .senses = SensorsSnapshot{},
        .recalled_episodes = &[_]*Episode{},
        .active_issues = &[_]u64{},
    };

    const episode = try createEpisode(allocator, context);

    // ID should be current timestamp (non-zero)
    try std.testing.expect(episode.id != 0);
}

test "Episode: calculateSimilarity with tag match" {
    const allocator = std.testing.allocator;

    const context = Context{
        .timestamp_ns = std.time.nanoTimestamp(),
        .policy = PolicySnapshot{},
        .senses = SensorsSnapshot{},
        .recalled_episodes = &[_]*Episode{},
        .active_issues = &[_]u64{},
    };

    const episode_a = Episode{
        .id = 1000,
        .timestamp = std.time.nanoTimestamp(),
        .source = .lotus_cycle,
        .context = context,
        .action = .{ .set = SetAction{
            .key = "test_tag",
            .value = .{ .string = "value1" },
        }},
        .result = Result{
            .success = true,
            .error = null,
            .timing = Timing{ .start_ns = 0, .end_ns = 0, .duration_ms = 10 },
            .output = null,
            .new_senses = SensorsSnapshot{},
        },
        .outcome = .success,
        .tags = &[_][]const u8{ "farm_action" },
    };

    const episode_b = Episode{
        .id = 1001,
        .timestamp = std.time.nanoTimestamp() - 1000000000,
        .source = .lotus_cycle,
        .context = context,
        .action = undefined,
        .result = undefined,
        .outcome = undefined,
        .tags = &[_][]const u8{ "farm_action" },
    };

    const context_b = Context{
        .timestamp_ns = std.time.nanoTimestamp(),
        .policy = PolicySnapshot{},
        .senses = SensorsSnapshot{},
        .recalled_episodes = &[_]*Episode{},
        .active_issues = &[_]u64{},
    };

    // episode_a has farm_action tag, episode_b has farm_action tag -> should get good score
    const score = try calculateSimilarity(allocator, episode_a, context_b, 0);

    // Should get at least tag overlap score (40)
    try std.testing.expect(score >= 40.0);
}

test "Episode: estimateQualityDelta with kill_threshold improvement" {
    const allocator = std.testing.allocator;

    const context = Context{
        .timestamp_ns = std.time.nanoTimestamp(),
        .policy = PolicySnapshot{
            .kill_threshold = 4.0,
            .crash_rate_limit = 0.2,
            .byzantine_rate_limit = 0.15,
        },
        .senses = SensorsSnapshot{
            .farm_best_ppl = 3.5,
        },
        .recalled_episodes = &[_]*Episode{},
        .active_issues = &[_]u64{},
    };

    // Increase threshold from 4.0 to 5.0, moving toward better PPL (3.5)
    const delta = PolicyDelta{
        .operation = .scale,
        .key = "kill_threshold",
        .old_value = .{ .f64 = 4.0 },
        .new_value = .{ .f64 = 5.0 },
        .expected_quality_delta = 0.5,
        .reason = "Reduce PPL by increasing threshold",
    };

    const quality = try estimateQualityDelta(delta, context);

    // Should get positive quality for moving toward better PPL
    try std.testing.expect(quality > 0.0);
}

test "Episode: estimateQualityDelta with kill_threshold degradation" {
    const allocator = std.testing.allocator;

    const context = Context{
        .timestamp_ns = std.time.nanoTimestamp(),
        .policy = PolicySnapshot{
            .kill_threshold = 5.0,
            .crash_rate_limit = 0.2,
            .byzantine_rate_limit = 0.15,
        },
        .senses = SensorsSnapshot{
            .farm_best_ppl = 3.5,
        },
        .recalled_episodes = &[_]*Episode{},
        .active_issues = &[_]u64{},
    };

    // Decrease threshold from 5.0 to 4.0, moving away from better PPL
    const delta = PolicyDelta{
        .operation = .scale,
        .key = "kill_threshold",
        .old_value = .{ .f64 = 5.0 },
        .new_value = .{ .f64 = 4.0 },
        .expected_quality_delta = 0.5,
        .reason = "Reduce PPL by increasing threshold",
    };

    const quality = try estimateQualityDelta(delta, context);

    // Should get negative quality for moving away from better PPL
    try std.testing.expect(quality < 0.0);
}
